//! Canonical data container for all repository metadata

use serde::{Deserialize, Serialize};
use super::{Repository, ManualProject, WebReference, Book};
use super::platform::PlatformStatus;
use std::collections::HashMap;

/// Root data structure containing all repository and documentation metadata
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CanonicalData {
    pub schema_version: String,
    pub last_updated: String,
    pub generated_by: String,
    pub total_count: usize,

    pub repositories: Vec<Repository>,

    #[serde(skip_serializing_if = "Vec::is_empty", default)]
    pub manual_projects: Vec<ManualProject>,

    #[serde(skip_serializing_if = "Vec::is_empty", default)]
    pub web_references: Vec<WebReference>,

    #[serde(skip_serializing_if = "Vec::is_empty", default)]
    pub books: Vec<Book>,

    /// Platform statistics
    #[serde(skip_serializing_if = "Option::is_none")]
    pub statistics: Option<RepositoryStatistics>,
}

/// Repository statistics by platform and status
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RepositoryStatistics {
    pub total: usize,
    pub by_platform: HashMap<String, usize>,
    pub by_status: StatusCounts,
    pub by_language: HashMap<String, usize>,
}

/// Count of repositories by status
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct StatusCounts {
    pub active: usize,
    pub archived: usize,
    pub deprecated: usize,
}

impl CanonicalData {
    /// Create new empty canonical data
    pub fn new() -> Self {
        Self {
            schema_version: "1.0".to_string(),
            last_updated: chrono::Utc::now().to_rfc3339(),
            generated_by: "omnidatum-processor".to_string(),
            total_count: 0,
            repositories: vec![],
            manual_projects: vec![],
            web_references: vec![],
            books: vec![],
            statistics: None,
        }
    }

    /// Load from YAML file
    pub fn from_yaml_file(path: &std::path::Path) -> crate::Result<Self> {
        let content = std::fs::read_to_string(path)?;
        let data: Self = serde_yaml::from_str(&content)?;
        Ok(data)
    }

    /// Load from JSON file
    pub fn from_json_file(path: &std::path::Path) -> crate::Result<Self> {
        let content = std::fs::read_to_string(path)?;
        let data: Self = serde_json::from_str(&content)?;
        Ok(data)
    }

    /// Save to YAML file
    pub fn to_yaml_file(&self, path: &std::path::Path) -> crate::Result<()> {
        let content = serde_yaml::to_string(self)?;
        std::fs::write(path, content)?;
        Ok(())
    }

    /// Save to JSON file
    pub fn to_json_file(&self, path: &std::path::Path) -> crate::Result<()> {
        let content = serde_json::to_string_pretty(self)?;
        std::fs::write(path, content)?;
        Ok(())
    }

    /// Calculate statistics from current data
    pub fn calculate_statistics(&mut self) {
        let mut by_platform: HashMap<String, usize> = HashMap::new();
        let mut by_language: HashMap<String, usize> = HashMap::new();
        let mut active = 0;
        let mut archived = 0;
        let mut deprecated = 0;

        // Count repositories
        for repo in &self.repositories {
            // Count by platform
            for platform in &repo.platforms {
                let platform_name = format!("{:?}", platform.platform);
                *by_platform.entry(platform_name).or_insert(0) += 1;

                // Count by status
                match platform.status {
                    super::platform::PlatformStatus::Active => active += 1,
                    super::platform::PlatformStatus::Archived => archived += 1,
                    super::platform::PlatformStatus::Deprecated => deprecated += 1,
                }
            }

            // Count by language
            let lang = &repo.classification.language_category;
            *by_language.entry(lang.clone()).or_insert(0) += 1;
        }

        // Count manual projects (convert to repository for counting)
        for manual in &self.manual_projects {
            // Count by platform
            for platform in &manual.platforms {
                let platform_name = format!("{:?}", platform.platform);
                *by_platform.entry(platform_name).or_insert(0) += 1;

                // Count by status
                match platform.status {
                    PlatformStatus::Active => active += 1,
                    PlatformStatus::Archived => archived += 1,
                    PlatformStatus::Deprecated => deprecated += 1,
                }
            }

            // Count by language
            let lang = &manual.metadata.primary_language;
            *by_language.entry(lang.clone()).or_insert(0) += 1;
        }

        self.statistics = Some(RepositoryStatistics {
            total: self.repositories.len() + self.manual_projects.len(),
            by_platform,
            by_status: StatusCounts {
                active,
                archived,
                deprecated,
            },
            by_language,
        });

        self.total_count = self.repositories.len() + self.manual_projects.len();
    }

    /// Get all repositories including converted manual projects
    pub fn all_repositories(&self) -> Vec<Repository> {
        let mut all = self.repositories.clone();
        all.extend(self.manual_projects.iter().map(|m| m.to_repository()));
        all
    }

    /// Get active repositories (excluding archive candidates)
    pub fn active_repositories(&self) -> Vec<Repository> {
        self.all_repositories()
            .into_iter()
            .filter(|r| !r.is_archive_candidate())
            .collect()
    }

    /// Get archived repositories
    pub fn archived_repositories(&self) -> Vec<Repository> {
        self.all_repositories()
            .into_iter()
            .filter(|r| r.is_archive_candidate())
            .collect()
    }

    /// Find repository by ID
    pub fn find_repo_by_id(&self, id: &str) -> Option<&Repository> {
        self.repositories.iter().find(|r| r.id == id)
    }

    /// Find repositories by language
    pub fn repos_by_language(&self, language: &str) -> Vec<&Repository> {
        self.repositories
            .iter()
            .filter(|r| r.classification.language_category == language)
            .collect()
    }
}

impl Default for CanonicalData {
    fn default() -> Self {
        Self::new()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_canonical_data_creation() {
        let data = CanonicalData::new();

        assert_eq!(data.schema_version, "1.0");
        assert_eq!(data.total_count, 0);
        assert_eq!(data.repositories.len(), 0);
    }

    #[test]
    fn test_active_vs_archived_filtering() {
        let mut data = CanonicalData::new();

        // Add one active and one archived repo
        // (This would require creating full Repository instances - simplified for now)

        data.total_count = 2;

        // In real implementation, would test the filtering logic
        assert_eq!(data.total_count, 2);
    }
}

//! Book metadata and relationship models

use serde::{Deserialize, Serialize};

/// Relationship between books
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "lowercase")]
pub enum BookRelationship {
    /// Books that should be read together
    Companion,
    /// Book that should be read before this one
    Prerequisite,
    /// Newer edition or follow-up
    Successor,
}

/// Related book reference
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RelatedBook {
    pub id: String,
    pub relationship: BookRelationship,

    #[serde(skip_serializing_if = "Option::is_none")]
    pub note: Option<String>,
}

/// Book entry for learning resources
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Book {
    pub id: String,
    pub title: String,

    #[serde(skip_serializing_if = "Option::is_none")]
    pub subtitle: Option<String>,

    pub authors: Vec<String>,
    pub category: String,

    #[serde(skip_serializing_if = "Option::is_none")]
    pub subcategory: Option<String>,

    #[serde(skip_serializing_if = "Option::is_none")]
    pub isbn: Option<String>,

    #[serde(skip_serializing_if = "Option::is_none")]
    pub publication_year: Option<u16>,

    #[serde(skip_serializing_if = "Option::is_none")]
    pub edition: Option<String>,

    /// Related books
    #[serde(skip_serializing_if = "Vec::is_empty", default)]
    pub related_books: Vec<RelatedBook>,

    /// Topics this book could expand into
    #[serde(skip_serializing_if = "Vec::is_empty", default)]
    pub expansion_topics: Vec<String>,

    /// Related web reference IDs
    #[serde(skip_serializing_if = "Vec::is_empty", default)]
    pub related_web_references: Vec<String>,

    /// Related repository IDs
    #[serde(skip_serializing_if = "Vec::is_empty", default)]
    pub related_repos: Vec<String>,
}

impl Book {
    /// Get full title including subtitle if present
    pub fn full_title(&self) -> String {
        if let Some(subtitle) = &self.subtitle {
            format!("{}: {}", self.title, subtitle)
        } else {
            self.title.clone()
        }
    }

    /// Get formatted author string
    pub fn authors_string(&self) -> String {
        match self.authors.len() {
            0 => "Unknown".to_string(),
            1 => self.authors[0].clone(),
            2 => format!("{} and {}", self.authors[0], self.authors[1]),
            _ => {
                let last = self.authors.last().unwrap();
                let others = &self.authors[..self.authors.len() - 1];
                format!("{}, and {}", others.join(", "), last)
            }
        }
    }

    /// Check if book has expansion opportunities
    pub fn has_expansion_topics(&self) -> bool {
        !self.expansion_topics.is_empty()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_full_title_with_subtitle() {
        let book = Book {
            id: "test-book".to_string(),
            title: "Designing Software Architectures".to_string(),
            subtitle: Some("A Practical Approach".to_string()),
            authors: vec!["Author Name".to_string()],
            category: "Architecture".to_string(),
            subcategory: None,
            isbn: None,
            publication_year: Some(2016),
            edition: None,
            related_books: vec![],
            expansion_topics: vec![],
            related_web_references: vec![],
            related_repos: vec![],
        };

        assert_eq!(
            book.full_title(),
            "Designing Software Architectures: A Practical Approach"
        );
    }

    #[test]
    fn test_authors_string_multiple() {
        let book = Book {
            id: "test-book".to_string(),
            title: "Test Book".to_string(),
            subtitle: None,
            authors: vec![
                "Author One".to_string(),
                "Author Two".to_string(),
                "Author Three".to_string(),
            ],
            category: "Test".to_string(),
            subcategory: None,
            isbn: None,
            publication_year: None,
            edition: None,
            related_books: vec![],
            expansion_topics: vec![],
            related_web_references: vec![],
            related_repos: vec![],
        };

        assert_eq!(
            book.authors_string(),
            "Author One, Author Two, and Author Three"
        );
    }

    #[test]
    fn test_has_expansion_topics() {
        let mut book = Book {
            id: "test-book".to_string(),
            title: "Test Book".to_string(),
            subtitle: None,
            authors: vec!["Author".to_string()],
            category: "Test".to_string(),
            subcategory: None,
            isbn: None,
            publication_year: None,
            edition: None,
            related_books: vec![],
            expansion_topics: vec![],
            related_web_references: vec![],
            related_repos: vec![],
        };

        assert!(!book.has_expansion_topics());

        book.expansion_topics.push("distributed-systems".to_string());
        assert!(book.has_expansion_topics());
    }
}

//! Web reference and documentation link models

use serde::{Deserialize, Serialize};

/// Type of reference content
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "lowercase")]
pub enum ContentType {
    Article,
    Documentation,
    Book,
    Video,
    Catalog,
    Tutorial,
    Paper,
}

/// Difficulty level of content
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "lowercase")]
pub enum DifficultyLevel {
    Introductory,
    Intermediate,
    Advanced,
}

/// Status of a web reference
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "lowercase")]
pub enum ReferenceStatus {
    Active,
    Proposed,
    Deprecated,
}

/// Web reference entry for documentation and learning resources
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct WebReference {
    pub id: String,
    pub title: String,
    pub url: String,

    #[serde(skip_serializing_if = "Option::is_none")]
    pub author: Option<String>,

    pub category: String,

    #[serde(skip_serializing_if = "Option::is_none")]
    pub subcategory: Option<String>,

    pub content_type: ContentType,
    pub difficulty: DifficultyLevel,

    #[serde(skip_serializing_if = "Option::is_none")]
    pub publication_date: Option<String>,

    #[serde(skip_serializing_if = "Option::is_none")]
    pub last_verified: Option<String>,

    /// Related web references (by ID)
    #[serde(skip_serializing_if = "Vec::is_empty", default)]
    pub related_references: Vec<String>,

    /// Related repository IDs
    #[serde(skip_serializing_if = "Vec::is_empty", default)]
    pub related_repos: Vec<String>,

    #[serde(skip_serializing_if = "Vec::is_empty", default)]
    pub tags: Vec<String>,

    #[serde(default = "default_status")]
    pub status: ReferenceStatus,
}

fn default_status() -> ReferenceStatus {
    ReferenceStatus::Active
}

impl WebReference {
    /// Check if reference is stale (>2 years since last verified)
    pub fn is_stale(&self) -> bool {
        if let Some(last_verified) = &self.last_verified {
            if let Ok(verified_date) = chrono::NaiveDate::parse_from_str(last_verified, "%Y-%m-%d") {
                let threshold = chrono::Utc::now().date_naive() - chrono::Days::new(730); // 2 years
                return verified_date < threshold;
            }
        }
        // If never verified or invalid date, consider stale
        true
    }

    /// Check if reference is AI/ML related
    pub fn is_aiml_related(&self) -> bool {
        self.category.to_lowercase().contains("ai") ||
        self.category.to_lowercase().contains("ml") ||
        self.tags.iter().any(|t| {
            let t = t.to_lowercase();
            t.contains("ai") || t.contains("ml") || t.contains("llm") || 
            t.contains("machine-learning") || t.contains("deep-learning")
        })
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_stale_reference_detection() {
        let ref_stale = WebReference {
            id: "test-ref".to_string(),
            title: "Old Article".to_string(),
            url: "https://example.com".to_string(),
            author: None,
            category: "Test".to_string(),
            subcategory: None,
            content_type: ContentType::Article,
            difficulty: DifficultyLevel::Intermediate,
            publication_date: None,
            last_verified: Some("2020-01-01".to_string()),
            related_references: vec![],
            related_repos: vec![],
            tags: vec![],
            status: ReferenceStatus::Active,
        };

        assert!(ref_stale.is_stale());
    }

    #[test]
    fn test_aiml_detection_by_category() {
        let ref_aiml = WebReference {
            id: "test-ref".to_string(),
            title: "AI Article".to_string(),
            url: "https://example.com".to_string(),
            author: None,
            category: "AI/ML".to_string(),
            subcategory: None,
            content_type: ContentType::Article,
            difficulty: DifficultyLevel::Intermediate,
            publication_date: None,
            last_verified: Some("2024-01-01".to_string()),
            related_references: vec![],
            related_repos: vec![],
            tags: vec![],
            status: ReferenceStatus::Active,
        };

        assert!(ref_aiml.is_aiml_related());
    }

    #[test]
    fn test_aiml_detection_by_tags() {
        let ref_aiml = WebReference {
            id: "test-ref".to_string(),
            title: "ML Article".to_string(),
            url: "https://example.com".to_string(),
            author: None,
            category: "General".to_string(),
            subcategory: None,
            content_type: ContentType::Article,
            difficulty: DifficultyLevel::Intermediate,
            publication_date: None,
            last_verified: Some("2024-01-01".to_string()),
            related_references: vec![],
            related_repos: vec![],
            tags: vec!["machine-learning".to_string(), "deep-learning".to_string()],
            status: ReferenceStatus::Active,
        };

        assert!(ref_aiml.is_aiml_related());
    }
}

//! Platform and migration tracking models

use serde::{Deserialize, Serialize};

/// Supported code hosting platforms
#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "lowercase")]
pub enum Platform {
    #[serde(rename = "github")]
    GitHub,
    #[serde(rename = "codeberg")]
    Codeberg,
    #[serde(rename = "gitlab")]
    GitLab,
    #[serde(rename = "gitea")]
    Gitea,
    #[serde(rename = "aws-codecommit")]
    AwsCodeCommit,
}

impl std::fmt::Display for Platform {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Platform::GitHub => write!(f, "GitHub"),
            Platform::Codeberg => write!(f, "Codeberg"),
            Platform::GitLab => write!(f, "GitLab"),
            Platform::Gitea => write!(f, "Gitea"),
            Platform::AwsCodeCommit => write!(f, "AWS CodeCommit"),
        }
    }
}

/// Repository status on a platform
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "lowercase")]
pub enum PlatformStatus {
    Active,
    Archived,
    Deprecated,
}

/// Information about a repository on a specific platform
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PlatformInfo {
    pub platform: Platform,
    pub url: String,
    pub status: PlatformStatus,
    pub is_primary: bool,

    #[serde(skip_serializing_if = "Option::is_none")]
    pub migration_date: Option<String>,

    #[serde(skip_serializing_if = "Option::is_none")]
    pub last_verified: Option<String>,

    #[serde(skip_serializing_if = "Option::is_none")]
    pub notes: Option<String>,
}

/// Migration status for repositories hosted on multiple platforms
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum MigrationStatus {
    /// Repository exists on single platform only
    None,
    /// Active on multiple platforms (mirror)
    Mirror,
    /// Moved from one platform to another
    Migrated,
    /// Original platform archived, moved to new platform
    ArchivedMigrated,
}

/// Historical record of platform migrations
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct MigrationHistory {
    pub date: String,
    pub from: Platform,
    pub to: Platform,

    #[serde(skip_serializing_if = "Option::is_none")]
    pub reason: Option<String>,
}

/// Complete migration tracking record
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct MigrationRecord {
    pub repo_id: String,
    pub migration_status: MigrationStatus,
    pub platforms: Vec<PlatformInfo>,

    #[serde(skip_serializing_if = "Vec::is_empty", default)]
    pub migration_history: Vec<MigrationHistory>,
}

impl MigrationRecord {
    /// Detect migration status from platform information
    pub fn detect_status(platforms: &[PlatformInfo]) -> MigrationStatus {
        let active_count = platforms.iter()
            .filter(|p| p.status == PlatformStatus::Active)
            .count();

        let archived_count = platforms.iter()
            .filter(|p| p.status == PlatformStatus::Archived)
            .count();

        match (platforms.len(), active_count, archived_count) {
            (1, _, _) => MigrationStatus::None,
            (n, a, _) if n > 1 && a == n => MigrationStatus::Mirror,
            (n, a, ar) if n > 1 && a > 0 && ar > 0 => MigrationStatus::ArchivedMigrated,
            (n, a, _) if n > 1 && a > 0 => MigrationStatus::Migrated,
            _ => MigrationStatus::None,
        }
    }

    /// Get the primary platform URL
    pub fn primary_url(&self) -> Option<&str> {
        self.platforms
            .iter()
            .find(|p| p.is_primary)
            .map(|p| p.url.as_str())
    }

    /// Get all alternative platform URLs
    pub fn alternative_urls(&self) -> Vec<(&Platform, &str)> {
        self.platforms
            .iter()
            .filter(|p| !p.is_primary)
            .map(|p| (&p.platform, p.url.as_str()))
            .collect()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_migration_status_detection_single_platform() {
        let platforms = vec![PlatformInfo {
            platform: Platform::GitHub,
            url: "https://github.com/test/repo".to_string(),
            status: PlatformStatus::Active,
            is_primary: true,
            migration_date: None,
            last_verified: None,
            notes: None,
        }];

        let status = MigrationRecord::detect_status(&platforms);
        assert_eq!(status, MigrationStatus::None);
    }

    #[test]
    fn test_migration_status_detection_mirror() {
        let platforms = vec![
            PlatformInfo {
                platform: Platform::GitHub,
                url: "https://github.com/test/repo".to_string(),
                status: PlatformStatus::Active,
                is_primary: true,
                migration_date: None,
                last_verified: None,
                notes: None,
            },
            PlatformInfo {
                platform: Platform::Codeberg,
