            },
        ];

        let status = MigrationRecord::detect_status(&platforms);
        assert_eq!(status, MigrationStatus::Mirror);
    }

    #[test]
    fn test_migration_status_detection_archived_migrated() {
        let platforms = vec![
            PlatformInfo {
