                notes: Some("Moved to Codeberg".to_string()),
            },
            PlatformInfo {
                platform: Platform::Codeberg,
                url: "https://codeberg.org/test/repo".to_string(),
                status: PlatformStatus::Active,
                is_primary: true,
                migration_date: Some("2024-01-15".to_string()),
                last_verified: None,
                notes: None,
