//! Cross-reference graph for bidirectional linking

use petgraph::graph::{DiGraph, NodeIndex};
use std::collections::HashMap;
use crate::models::CanonicalData;

/// Node type in the cross-reference graph
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub enum NodeType {
    Repository(String),       // repo ID
    WebReference(String),     // reference ID
    Book(String),             // book ID
    ReadmeSection(String),    // section name
}

/// Edge type representing relationship
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum RelationType {
    Implements,      // Repo implements concept
    References,      // Section references repo
    Alternative,     // Alternative implementation
    Prerequisite,    // Required before
}

/// Cross-reference graph
pub struct CrossRefGraph {
    graph: DiGraph<NodeType, RelationType>,
    node_map: HashMap<NodeType, NodeIndex>,
}

impl CrossRefGraph {
    /// Create new empty graph
    pub fn new() -> Self {
        Self {
            graph: DiGraph::new(),
            node_map: HashMap::new(),
        }
    }

    /// Build graph from canonical data
    pub fn build(data: &CanonicalData) -> crate::Result<Self> {
        let mut graph = Self::new();

        // Add repository nodes
        for repo in &data.repositories {
            graph.add_node(NodeType::Repository(repo.id.clone()));
        }

        // Add web reference nodes and links to repos
        for reference in &data.web_references {
            let ref_node = NodeType::WebReference(reference.id.clone());
            graph.add_node(ref_node.clone());

            // Link to related repositories
            for repo_ref in &reference.related_repos {
                // Find repository by full_name or id
                if let Some(repo) = data.repositories.iter().find(|r| 
                    r.metadata.full_name == *repo_ref || r.id == *repo_ref
                ) {
                    graph.add_edge(
                        ref_node.clone(),
                        NodeType::Repository(repo.id.clone()),
                        RelationType::References,
                    );
                }
            }

            // Create README section nodes for web ref categories
            let section_node = NodeType::ReadmeSection(
                format!("Web References/{}", reference.category)
            );
            graph.add_node(section_node.clone());
            graph.add_edge(
                section_node,
                ref_node,
                RelationType::References,
            );
        }

        // Add book nodes and links
        for book in &data.books {
            let book_node = NodeType::Book(book.id.clone());
            graph.add_node(book_node.clone());

            // Link to related repositories
            for repo_ref in &book.related_repos {
                if let Some(repo) = data.repositories.iter().find(|r| 
                    r.metadata.full_name == *repo_ref || r.id == *repo_ref
                ) {
                    graph.add_edge(
                        book_node.clone(),
                        NodeType::Repository(repo.id.clone()),
                        RelationType::References,
                    );
                }
            }

            // Create README section node for books
            let section_node = NodeType::ReadmeSection("Books".to_string());
            graph.add_node(section_node.clone());
            graph.add_edge(
                section_node,
                book_node,
                RelationType::References,
            );
        }

        // Add README section nodes for repos that meet inclusion criteria
        for repo in &data.repositories {
            if repo.meets_readme_criteria() {
                for section in &repo.classification.readme_sections {
                    let section_node = NodeType::ReadmeSection(section.clone());
                    graph.add_node(section_node.clone());
                    graph.add_edge(
                        section_node,
                        NodeType::Repository(repo.id.clone()),
                        RelationType::References,
                    );
                }
            }
        }

        Ok(graph)
    }

    /// Add a node to the graph
    fn add_node(&mut self, node: NodeType) {
        if !self.node_map.contains_key(&node) {
            let idx = self.graph.add_node(node.clone());
            self.node_map.insert(node, idx);
        }
    }

    /// Add an edge between nodes
    fn add_edge(&mut self, from: NodeType, to: NodeType, rel: RelationType) {
        let from_idx = self.node_map[&from];
        let to_idx = self.node_map[&to];
        self.graph.add_edge(from_idx, to_idx, rel);
    }

    /// Get all repositories referenced by a README section
    pub fn repos_for_section(&self, section: &str) -> Vec<String> {
        let section_node = NodeType::ReadmeSection(section.to_string());

        if let Some(&node_idx) = self.node_map.get(&section_node) {
            let mut repos = Vec::new();

            // Find all outgoing edges
            use petgraph::visit::EdgeRef;
            for edge in self.graph.edges(node_idx) {
                if let NodeType::Repository(repo_id) = &self.graph[edge.target()] {
                    repos.push(repo_id.clone());
                }
            }

            repos
        } else {
            vec![]
        }
    }

    /// Get all README sections that reference a repository
    pub fn sections_for_repo(&self, repo_id: &str) -> Vec<String> {
        let repo_node = NodeType::Repository(repo_id.to_string());

        if let Some(&node_idx) = self.node_map.get(&repo_node) {
            let mut sections = Vec::new();

            // Find all incoming edges from README sections
            use petgraph::visit::EdgeRef;
            for edge in self.graph.edges_directed(node_idx, petgraph::Direction::Incoming) {
                if let NodeType::ReadmeSection(section) = &self.graph[edge.source()] {
                    sections.push(section.clone());
                }
            }

            sections
        } else {
            vec![]
        }
    }

    /// Get statistics about the graph
    pub fn stats(&self) -> CrossRefStats {
        let mut repo_count = 0;
        let mut web_ref_count = 0;
        let mut book_count = 0;
        let mut section_count = 0;

        for node in self.graph.node_weights() {
            match node {
                NodeType::Repository(_) => repo_count += 1,
                NodeType::WebReference(_) => web_ref_count += 1,
                NodeType::Book(_) => book_count += 1,
                NodeType::ReadmeSection(_) => section_count += 1,
            }
        }

        CrossRefStats {
            total_nodes: self.graph.node_count(),
            total_edges: self.graph.edge_count(),
            repositories: repo_count,
            web_references: web_ref_count,
            books: book_count,
            readme_sections: section_count,
        }
    }
}

/// Statistics about cross-reference graph
#[derive(Debug, Clone, serde::Serialize)]
pub struct CrossRefStats {
    pub total_nodes: usize,
    pub total_edges: usize,
    pub repositories: usize,
    pub web_references: usize,
    pub books: usize,
    pub readme_sections: usize,
}

impl Default for CrossRefGraph {
    fn default() -> Self {
        Self::new()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_graph_creation() {
        let graph = CrossRefGraph::new();
        let stats = graph.stats();

        assert_eq!(stats.total_nodes, 0);
        assert_eq!(stats.total_edges, 0);
    }

    #[test]
    fn test_node_addition() {
        let mut graph = CrossRefGraph::new();

        graph.add_node(NodeType::Repository("repo1".to_string()));
        graph.add_node(NodeType::WebReference("ref1".to_string()));

        let stats = graph.stats();
        assert_eq!(stats.repositories, 1);
        assert_eq!(stats.web_references, 1);
    }
}

//! Cross-reference detection and management

mod graph;
mod navigator;

pub use graph::*;
pub use navigator::*;

//! Navigation link generator for README cross-references

use super::graph::CrossRefGraph;
use crate::models::CanonicalData;
use std::collections::HashMap;

/// Navigation links generator
pub struct Navigator {
    graph: CrossRefGraph,
}

impl Navigator {
    /// Create navigator from canonical data
    pub fn new(data: &CanonicalData) -> crate::Result<Self> {
        let graph = CrossRefGraph::build(data)?;
        Ok(Self { graph })
    }

    /// Generate "Related Repositories" section for a web reference category
    pub fn related_repos_for_category(&self, data: &CanonicalData, category: &str) -> String {
        let section_name = format!("Web References/{}", category);
        let repo_ids = self.graph.repos_for_section(&section_name);

        if repo_ids.is_empty() {
            return String::new();
        }

        // Group repositories by language
        let mut by_language: HashMap<String, Vec<String>> = HashMap::new();

        for repo_id in &repo_ids {
            if let Some(repo) = data.find_repo_by_id(repo_id) {
                by_language
                    .entry(repo.classification.language_category.clone())
                    .or_insert_with(Vec::new)
                    .push(repo.metadata.full_name.clone());
            }
        }

        // Sort languages
        let mut langs: Vec<_> = by_language.keys().cloned().collect();
        langs.sort();

        // Format as markdown
        let mut output = String::from("*Related repositories: ");
        let lang_links: Vec<String> = langs.iter().map(|lang| {
            let repos = &by_language[lang];
            let repo_links: Vec<String> = repos.iter()
                .map(|r| format!("[{}](LIST.md#{})", r, lang.to_lowercase().replace(" ", "-")))
                .collect();
            format!("[{}](LIST.md#{}) - {}", lang, lang.to_lowercase().replace(" ", "-"), repo_links.join(", "))
        }).collect();

        output.push_str(&lang_links.join("; "));
        output.push_str("*");

        output
    }

    /// Generate cross-reference notation for a repository
    pub fn cross_ref_for_repo(&self, repo_id: &str) -> Option<String> {
        let sections = self.graph.sections_for_repo(repo_id);

        if sections.is_empty() {
            return None;
        }

        let section_links: Vec<String> = sections.iter()
            .map(|s| format!("[{}](README.md#{})", s, s.to_lowercase().replace(" ", "-").replace("/", "")))
            .collect();

        Some(format!("📑 Referenced in: {}", section_links.join(", ")))
    }

    /// Generate navigation index mapping repos to README sections
    pub fn build_navigation_index(&self, data: &CanonicalData) -> NavigationIndex {
        let mut readme_to_repos: HashMap<String, Vec<String>> = HashMap::new();
        let mut repo_to_readme: HashMap<String, Vec<String>> = HashMap::new();

        // Build from web references
        for reference in &data.web_references {
            let section = format!("Web References/{}", reference.category);

            for repo_ref in &reference.related_repos {
                if let Some(repo) = data.repositories.iter().find(|r| 
                    r.metadata.full_name == *repo_ref || r.id == *repo_ref
                ) {
                    readme_to_repos
                        .entry(section.clone())
                        .or_insert_with(Vec::new)
                        .push(repo.id.clone());

                    repo_to_readme
                        .entry(repo.id.clone())
                        .or_insert_with(Vec::new)
                        .push(section.clone());
                }
            }
        }

        // Build from books
        for book in &data.books {
            let section = "Books".to_string();

            for repo_ref in &book.related_repos {
                if let Some(repo) = data.repositories.iter().find(|r| 
                    r.metadata.full_name == *repo_ref || r.id == *repo_ref
                ) {
                    readme_to_repos
                        .entry(section.clone())
                        .or_insert_with(Vec::new)
                        .push(repo.id.clone());

                    repo_to_readme
                        .entry(repo.id.clone())
                        .or_insert_with(Vec::new)
                        .push(section.clone());
                }
            }
        }

        NavigationIndex {
            readme_to_repos,
            repo_to_readme,
        }
    }

    /// Get graph statistics
    pub fn stats(&self) -> super::graph::CrossRefStats {
        self.graph.stats()
    }
}

/// Navigation index for cross-references
#[derive(Debug, Clone)]
pub struct NavigationIndex {
    /// Map from README section to repository IDs
    pub readme_to_repos: HashMap<String, Vec<String>>,
    /// Map from repository ID to README sections
    pub repo_to_readme: HashMap<String, Vec<String>>,
}

impl NavigationIndex {
    /// Get repositories for a README section
    pub fn repos_for_section(&self, section: &str) -> Vec<&str> {
        self.readme_to_repos
            .get(section)
            .map(|repos| repos.iter().map(|s| s.as_str()).collect())
            .unwrap_or_default()
    }

    /// Get README sections for a repository
    pub fn sections_for_repo(&self, repo_id: &str) -> Vec<&str> {
        self.repo_to_readme
            .get(repo_id)
            .map(|sections| sections.iter().map(|s| s.as_str()).collect())
            .unwrap_or_default()
    }
}

