//! README update mechanism with HTML comment injection

use regex::Regex;

/// README updater that preserves manual content
pub struct ReadmeUpdater {
    _marker_start: Regex,
    _marker_end: Regex,
}

impl ReadmeUpdater {
    pub fn new() -> crate::Result<Self> {
        Ok(Self {
            _marker_start: Regex::new(r"<!--\s*AUTO-GENERATED:START[^>]*-->")?,
            _marker_end: Regex::new(r"<!--\s*AUTO-GENERATED:END\s*-->")?,
        })
    }

    /// Update README with generated content between markers
    pub fn update(&self, readme: &str, section: &str, content: &str) -> String {
        let marker_start = format!("<!-- AUTO-GENERATED:START {} -->", section);
        let marker_end = "<!-- AUTO-GENERATED:END -->";

        if readme.contains(&marker_start) {
            // Replace existing marked section
            let re = Regex::new(&format!(
                r"(?s){}.*?{}",
                regex::escape(&marker_start),
                regex::escape(marker_end)
            )).unwrap();

            let replacement = format!("{}\n{}\n{}", marker_start, content, marker_end);
            re.replace(readme, replacement.as_str()).to_string()
        } else {
            // Append new section at end
            format!("{}\n\n{}\n{}\n{}\n", readme, marker_start, content, marker_end)
        }
    }
}

impl Default for ReadmeUpdater {
    fn default() -> Self {
        Self::new().unwrap()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_update_existing_section() {
        let updater = ReadmeUpdater::new().unwrap();
        let readme = "# README\n<!-- AUTO-GENERATED:START test -->\nOld content\n<!-- AUTO-GENERATED:END -->\n";

        let result = updater.update(readme, "test", "New content");

        assert!(result.contains("New content"));
        assert!(!result.contains("Old content"));
    }

    #[test]
    fn test_add_new_section() {
        let updater = ReadmeUpdater::new().unwrap();
        let readme = "# README\nManual content";

        let result = updater.update(readme, "test", "Generated content");

        assert!(result.contains("Manual content"));
        assert!(result.contains("Generated content"));
        assert!(result.contains("<!-- AUTO-GENERATED:START test -->"));
    }
}

//! OmniDatum Processor - Enhanced documentation processor for GitHub starred repositories

use clap::{Parser, Subcommand};
use omnidatum_processor::{CanonicalData, Result};
use std::path::PathBuf;

#[derive(Parser)]
#[command(name = "omnidatum-processor")]
#[command(author = "encodedfox")]
#[command(version = "0.1.0")]
#[command(about = "Enhanced documentation processor for OmniDatum repository", long_about = None)]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    /// Parse existing LIST.md and TABLE.md into canonical format
    Parse {
        /// Path to LIST.md file
        #[arg(short, long, default_value = "LIST.md")]
        list: PathBuf,

        /// Path to TABLE.md file
        #[arg(short, long, default_value = "TABLE.md")]
        table: PathBuf,

        /// Output path for canonical data
        #[arg(short, long, default_value = "data/canonical/repositories.yml")]
        output: PathBuf,
    },

    /// Validate canonical data
    Validate {
        /// Path to canonical data file (YAML or JSON)
        #[arg(short, long, default_value = "data/canonical/repositories.yml")]
        input: PathBuf,

        /// Output path for validation report
        #[arg(short, long, default_value = "data/cache/validation_report.json")]
        output: PathBuf,
    },

    /// Generate markdown documents from canonical data
    Generate {
        /// Path to canonical data file
        #[arg(short, long, default_value = "data/canonical/repositories.yml")]
        input: PathBuf,

        /// Include archived repositories in separate files
        #[arg(long, default_value = "true")]
        include_archived: bool,

        /// Validate data before generating
        #[arg(long, default_value = "false")]
        validate: bool,

        /// Include multi-platform information in output
        #[arg(long, default_value = "false")]
        platforms: bool,
    },

    /// Merge manual additions into canonical data
    Merge {
        /// Path to base canonical data
        #[arg(short, long, default_value = "data/canonical/repositories.yml")]
        base: PathBuf,

        /// Path to manual additions YAML
        #[arg(short, long, default_value = "data/canonical/manual_additions.yml")]
        manual: PathBuf,

        /// Output path for merged canonical data
        #[arg(short, long, default_value = "data/canonical/repositories.yml")]
        output: PathBuf,
    },

    /// Show statistics about repository data
    Stats {
        /// Path to canonical data file
        #[arg(short, long, default_value = "data/canonical/repositories.yml")]
        input: PathBuf,

        /// Output as enhanced JSON with detailed metadata
        #[arg(long, default_value = "false")]
        enhanced_json: bool,

        /// Compare with previous statistics
        #[arg(long)]
        diff: Option<PathBuf>,
    },
}

fn main() -> Result<()> {
    env_logger::init();

    let cli = Cli::parse();

    match cli.command {
        Commands::Parse { list, table: _, output } => {
            println!("📖 Parsing markdown files...");
            println!("  LIST: {}", list.display());
            println!("  Output: {}", output.display());

            // Read LIST.md
            let list_content = std::fs::read_to_string(&list)?;

            // Parse repositories
            let parser = omnidatum_processor::ListParser::new()?;
            let repos = parser.parse_file(&list_content)?;

            println!("\n✅ Successfully parsed {} repositories!", repos.len());

            // Create canonical data
            let mut canonical = CanonicalData::new();
            canonical.repositories = repos;
            canonical.total_count = canonical.repositories.len();
            canonical.generated_by = "omnidatum-processor/list-parser".to_string();
            canonical.calculate_statistics();

            // Create output directory if it doesn't exist
            if let Some(parent) = output.parent() {
                std::fs::create_dir_all(parent)?;
            }

            // Save to YAML
            canonical.to_yaml_file(&output)?;

            println!("📝 Canonical data saved to: {}", output.display());

            if let Some(stats) = &canonical.statistics {
                println!("\n📊 Statistics:");
                println!("  Total repositories: {}", stats.total);
                println!("  Active: {}", stats.by_status.active);
                println!("  Archived: {}", stats.by_status.archived);
                println!("  Languages: {}", stats.by_language.len());
            }

            Ok(())
        }

        Commands::Validate { input, output } => {
            println!("✅ Validating data...");
            println!("  Input: {}", input.display());
            println!("  Report: {}", output.display());

            // Load canonical data
            let data = if input.extension().and_then(|s| s.to_str()) == Some("json") {
                CanonicalData::from_json_file(&input)?
            } else {
                CanonicalData::from_yaml_file(&input)?
            };

            println!("\n📊 Data loaded:");
            println!("  Repositories: {}", data.repositories.len());
            println!("  Manual projects: {}", data.manual_projects.len());
            println!("  Web references: {}", data.web_references.len());
            println!("  Books: {}", data.books.len());

            // Create validator and add rules
            let mut validator = omnidatum_processor::Validator::new();
            validator.add_rule(omnidatum_processor::NoDuplicateReposRule);
            validator.add_rule(omnidatum_processor::MissingLicenseRule {
                allow_low_star_repos: true,
            });
            validator.add_rule(omnidatum_processor::ValidUrlsRule::new()?);
            validator.add_rule(omnidatum_processor::ReadmeCrossReferenceRule);
            validator.add_rule(omnidatum_processor::PlatformMigrationRule);
            validator.add_rule(omnidatum_processor::MissingMetadataRule);
            validator.add_rule(omnidatum_processor::StaleContentRule {
                stale_days: 730,  // 2 years
            });

            println!("\n🔍 Running validation rules...");

            // Run validation
            let report = validator.validate(&data);

            // Display summary
            println!("\n📋 Validation Summary:");
            println!("  Errors: {}", report.summary.errors);
            println!("  Warnings: {}", report.summary.warnings);
            println!("  Info: {}", report.summary.info);
            println!("  Total repos: {}", report.summary.total_repos);

            println!("\n📊 Metrics:");
            println!("  Platforms:");
            for (platform, count) in &report.metrics.repos_by_platform {
                println!("    {}: {}", platform, count);
            }
            println!("  Archived: {}", report.metrics.archived_count);
            println!("  Missing licenses: {}", report.metrics.missing_licenses);
            println!("  Stale references: {}", report.metrics.stale_references);
            println!("  Migrations: {}", report.metrics.migration_count);

            // Save report
            report.to_json_file(&output)?;
            println!("\n💾 Report saved to: {}", output.display());

            // Exit with error code if validation failed
            if !report.passed() {
                println!("\n❌ Validation FAILED - {} errors found", report.summary.errors);
                std::process::exit(1);
            } else {
                println!("\n✅ Validation PASSED - No errors found!");
            }

            Ok(())
        }

        Commands::Generate { input, include_archived, validate, platforms } => {
            println!("📝 Generating documents...");
            println!("  Input: {}", input.display());
            println!("  Include archived: {}", include_archived);
            println!("  Validate before generation: {}", validate);
            println!("  Include platform info: {}", platforms);

            // Load canonical data
            let data = if input.extension().and_then(|s| s.to_str()) == Some("json") {
                CanonicalData::from_json_file(&input)?
            } else {
                CanonicalData::from_yaml_file(&input)?
            };

            // Run validation if requested
            if validate {
                println!("\n🔍 Running pre-generation validation...");
                let mut validator = omnidatum_processor::Validator::new();
                validator.add_rule(omnidatum_processor::NoDuplicateReposRule);
                validator.add_rule(omnidatum_processor::ValidUrlsRule::new()?);

                let report = validator.validate(&data);
                if !report.passed() {
                    println!("❌ Validation failed with {} errors", report.summary.errors);
                    std::process::exit(1);
                }
                println!("✅ Validation passed");
            }

            println!("\n📊 Data loaded:");
            println!("  Total repositories: {}", data.total_count);

            // Create generator
            let generator = omnidatum_processor::MarkdownGenerator::new("data/templates")?;

            // Separate active and archived repositories
            let mut active_data = data.clone();
            active_data.repositories = data.active_repositories();
            active_data.calculate_statistics();

            let mut archive_data = data.clone();
            archive_data.repositories = data.archived_repositories();
            archive_data.calculate_statistics();

            println!("  Active: {}", active_data.repositories.len());
            println!("  Archived: {}", archive_data.repositories.len());

            // Generate LIST.md (active only)
            println!("\n📄 Generating LIST.md...");
            let list_content = generator.generate_list(&active_data, true)?;
            std::fs::write("LIST.md", list_content)?;
            println!("  ✅ LIST.md generated");

            // Generate TABLE.md (active only)
            println!("📄 Generating TABLE.md...");
            let table_content = generator.generate_table(&active_data, true)?;
            std::fs::write("TABLE.md", table_content)?;
            println!("  ✅ TABLE.md generated");

            if include_archived && !archive_data.repositories.is_empty() {
                // Generate ARCHIVE.md
                println!("📄 Generating ARCHIVE.md...");
                let archive_list = generator.generate_list(&archive_data, true)?;
                std::fs::write("ARCHIVE.md", archive_list)?;
                println!("  ✅ ARCHIVE.md generated");

                // Generate ARCHIVE_TABLE.md
                println!("📄 Generating ARCHIVE_TABLE.md...");
                let archive_table = generator.generate_table(&archive_data, true)?;
                std::fs::write("ARCHIVE_TABLE.md", archive_table)?;
                println!("  ✅ ARCHIVE_TABLE.md generated");
            }

            println!("\n✅ Generation complete!");
            println!("  LIST.md: {} repos", active_data.repositories.len());
            println!("  TABLE.md: {} repos", active_data.repositories.len());
            if include_archived {
                println!("  ARCHIVE.md: {} repos", archive_data.repositories.len());
                println!("  ARCHIVE_TABLE.md: {} repos", archive_data.repositories.len());
            }

            Ok(())
        }

        Commands::Merge { base, manual, output } => {
            println!("🔀 Merging data sources...");
            println!("  Base: {}", base.display());
            println!("  Manual: {}", manual.display());
            println!("  Output: {}", output.display());

            // Load base data (repositories from starred lists)
            let base_data = if base.extension().and_then(|s| s.to_str()) == Some("json") {
                CanonicalData::from_json_file(&base)?
            } else {
                CanonicalData::from_yaml_file(&base)?
            };

            println!("\n📊 Base data loaded:");
            println!("  Repositories: {}", base_data.repositories.len());

            // Load manual additions if file exists
            let manual_data = if manual.exists() {
                let data = CanonicalData::from_yaml_file(&manual)?;
                println!("  Manual projects: {}", data.manual_projects.len());
                Some(data)
            } else {
                println!("  No manual additions file found, skipping");
                None
            };

            // Load web references if file exists
            let web_refs_path = manual.parent()
                .map(|p| p.join("web_references.yml"))
                .unwrap_or_else(|| "data/canonical/web_references.yml".into());

            let web_refs = if web_refs_path.exists() {
                let content = std::fs::read_to_string(&web_refs_path)?;
                #[derive(serde::Deserialize)]
                struct WebRefFile {
                    references: Vec<omnidatum_processor::WebReference>,
                }
                let file: WebRefFile = serde_yaml::from_str(&content)?;
                println!("  Web references: {}", file.references.len());
                Some(file.references)
            } else {
                println!("  No web references file found, skipping");
                None
            };

            // Load books if file exists
            let books_path = manual.parent()
                .map(|p| p.join("books.yml"))
                .unwrap_or_else(|| "data/canonical/books.yml".into());

            let books = if books_path.exists() {
                let content = std::fs::read_to_string(&books_path)?;
                #[derive(serde::Deserialize)]
                struct BookFile {
                    books: Vec<omnidatum_processor::Book>,
                }
                let file: BookFile = serde_yaml::from_str(&content)?;
                println!("  Books: {}", file.books.len());
                Some(file.books)
            } else {
                println!("  No books file found, skipping");
                None
            };

            // Perform merge
            println!("\n🔄 Merging data...");
            let merger = omnidatum_processor::DataMerger::new(
                omnidatum_processor::MergeStrategy::PreferManual
            );

            let mut merged = merger.merge(base_data, manual_data, web_refs, books)?;

            // Enhance data
            println!("🔍 Detecting migrations...");
            let migrations = merger.detect_migrations(&mut merged)?;
            if migrations > 0 {
                println!("  Found {} potential migrations", migrations);
            }

            println!("📊 Calculating quality scores...");
            merger.calculate_quality_scores(&mut merged)?;

            // Save merged data
            merged.to_yaml_file(&output)?;
            println!("\n💾 Merged data saved to: {}", output.display());

            println!("\n✅ Merge Summary:");
            println!("  Total repositories: {}", merged.total_count);
            println!("  Starred repos: {}", merged.repositories.len());
            println!("  Manual projects: {}", merged.manual_projects.len());
            println!("  Web references: {}", merged.web_references.len());
            println!("  Books: {}", merged.books.len());

            if let Some(stats) = &merged.statistics {
                println!("\n📊 Platform Distribution:");
                for (platform, count) in &stats.by_platform {
                    println!("  {}: {}", platform, count);
                }
            }

            Ok(())
        }

        Commands::Stats { input, enhanced_json, diff } => {
            println!("📊 Repository Statistics");
            println!("  Input: {}", input.display());

            // Load data
            let mut data = if input.extension().and_then(|s| s.to_str()) == Some("json") {
                CanonicalData::from_json_file(&input)?
            } else {
                CanonicalData::from_yaml_file(&input)?
            };

            // Ensure statistics are calculated
            data.calculate_statistics();

            // Handle enhanced JSON output
            if enhanced_json {
                let json = serde_json::to_string_pretty(&data)?;
                println!("\n{}", json);
                return Ok(());
            }

            // Handle diff comparison
            if let Some(diff_path) = diff {
                println!("\n📊 Comparing with: {}", diff_path.display());
                let prev_data = if diff_path.extension().and_then(|s| s.to_str()) == Some("json") {
                    CanonicalData::from_json_file(&diff_path)?
                } else {
                    CanonicalData::from_yaml_file(&diff_path)?
                };

                let repo_diff = data.repositories.len() as i32 - prev_data.repositories.len() as i32;
                let sign = if repo_diff > 0 { "+" } else { "" };
                println!("  Repository count: {}{}", sign, repo_diff);

                if let (Some(curr_stats), Some(prev_stats)) = (&data.statistics, &prev_data.statistics) {
                    let active_diff = curr_stats.by_status.active as i32 - prev_stats.by_status.active as i32;
                    let archived_diff = curr_stats.by_status.archived as i32 - prev_stats.by_status.archived as i32;
                    println!("  Active repos: {}{}", if active_diff > 0 { "+" } else { "" }, active_diff);
                    println!("  Archived repos: {}{}", if archived_diff > 0 { "+" } else { "" }, archived_diff);
                }
            }

            println!("\n📈 Overall Statistics:");
            println!("  Schema version: {}", data.schema_version);
            println!("  Total repositories: {}", data.total_count);
            println!("  Starred repos: {}", data.repositories.len());
            println!("  Manual projects: {}", data.manual_projects.len());
            println!("  Web references: {}", data.web_references.len());
            println!("  Books: {}", data.books.len());

            if let Some(stats) = &data.statistics {
                println!("\n📊 By Platform:");
                for (platform, count) in &stats.by_platform {
                    let pct = (count * 100) as f32 / stats.total as f32;
                    println!("  {}: {} ({:.1}%)", platform, count, pct);
                }

                println!("\n📊 By Status:");
                println!("  Active: {} ({:.1}%)", stats.by_status.active,
                        (stats.by_status.active * 100) as f32 / stats.total as f32);
                println!("  Archived: {} ({:.1}%)", stats.by_status.archived,
                        (stats.by_status.archived * 100) as f32 / stats.total as f32);

                println!("\n📊 By Language (top 10):");
                let mut langs: Vec<_> = stats.by_language.iter().collect();
                langs.sort_by(|a, b| b.1.cmp(a.1));
                for (lang, count) in langs.iter().take(10) {
                    let pct = (**count * 100) as f32 / stats.total as f32;
                    println!("  {}: {} ({:.1}%)", lang, count, pct);
                }

                println!("\n📊 Archive Candidates:");
                let archive_candidates = data.all_repositories()
                    .iter()
                    .filter(|r| r.is_archive_candidate())
                    .count();
                println!("  Total: {} ({:.1}%)", archive_candidates,
                        (archive_candidates * 100) as f32 / stats.total as f32);

                println!("\n📊 README Inclusion Candidates:");
                let readme_candidates = data.all_repositories()
                    .iter()
                    .filter(|r| r.meets_readme_criteria())
                    .count();
                println!("  Total: {} ({:.1}%)", readme_candidates,
                        (readme_candidates * 100) as f32 / stats.total as f32);
            }

            Ok(())
        }
    }
}

//! Validation rules implementation

use super::framework::*;
use crate::models::CanonicalData;
use std::collections::HashSet;
use regex::Regex;

/// Rule E001: Check for duplicate repository URLs
pub struct NoDuplicateReposRule;

impl ValidationRule for NoDuplicateReposRule {
    fn name(&self) -> &str {
        "no_duplicate_repos"
    }

    fn default_severity(&self) -> Severity {
        Severity::Error
    }

    fn check(&self, data: &CanonicalData) -> ValidationResult {
        let mut seen_urls: HashSet<String> = HashSet::new();
        let mut issues = Vec::new();

        for repo in &data.repositories {
            for platform in &repo.platforms {
                let url = platform.url.to_lowercase();

                if seen_urls.contains(&url) {
                    issues.push(ValidationIssue {
                        code: ValidationErrorCode::DuplicateRepo,
                        severity: self.default_severity(),
                        message: format!("Duplicate repository URL: {}", platform.url),
                        location: ValidationLocation {
                            file: "repositories.yml".to_string(),
                            line: None,
                            section: Some(repo.id.clone()),
                        },
                        suggestion: "Remove duplicate or merge repository entries".to_string(),
                        auto_fixable: false,
                    });
                } else {
                    seen_urls.insert(url);
                }
            }
        }

        ValidationResult::multiple(issues)
    }
}

/// Rule E002: Check for missing license information
pub struct MissingLicenseRule {
    /// Allow repos with <10 stars to skip license requirement
    pub allow_low_star_repos: bool,
}

impl ValidationRule for MissingLicenseRule {
    fn name(&self) -> &str {
        "missing_license"
    }

    fn default_severity(&self) -> Severity {
        Severity::Warning  // Changed to warning since many repos don't specify
    }

    fn check(&self, data: &CanonicalData) -> ValidationResult {
        let mut issues = Vec::new();

        for repo in &data.repositories {
            if repo.metadata.license.is_none() {
                // Skip low-star repos if configured
                if self.allow_low_star_repos && repo.metadata.stars < 10 {
                    continue;
                }

                issues.push(ValidationIssue {
                    code: ValidationErrorCode::MissingLicense,
                    severity: self.default_severity(),
                    message: format!("Repository missing license: {}", repo.metadata.full_name),
                    location: ValidationLocation {
                        file: "repositories.yml".to_string(),
                        line: None,
                        section: Some(repo.id.clone()),
                    },
                    suggestion: "Add license information or mark as unlicensed".to_string(),
                    auto_fixable: false,
                });
            }
        }

        ValidationResult::multiple(issues)
    }
}

/// Rule E003: Check for valid URL formats
pub struct ValidUrlsRule {
    url_regex: Regex,
}

impl ValidUrlsRule {
    pub fn new() -> crate::Result<Self> {
        Ok(Self {
            url_regex: Regex::new(r"^https?://[a-zA-Z0-9\-._~:/?#\[\]@!$&'()*+,;=]+$")?,
        })
    }
}

impl ValidationRule for ValidUrlsRule {
    fn name(&self) -> &str {
        "valid_urls"
    }

    fn default_severity(&self) -> Severity {
        Severity::Error
    }

    fn check(&self, data: &CanonicalData) -> ValidationResult {
        let mut issues = Vec::new();

        // Check repository URLs
        for repo in &data.repositories {
            for platform in &repo.platforms {
                if !self.url_regex.is_match(&platform.url) {
                    issues.push(ValidationIssue {
                        code: ValidationErrorCode::InvalidUrl,
                        severity: self.default_severity(),
                        message: format!("Invalid URL format: {}", platform.url),
                        location: ValidationLocation {
                            file: "repositories.yml".to_string(),
                            line: None,
                            section: Some(repo.id.clone()),
                        },
                        suggestion: "Fix URL format to be valid http/https URL".to_string(),
                        auto_fixable: false,
                    });
                }
            }
        }

        // Check web reference URLs
        for reference in &data.web_references {
            if !self.url_regex.is_match(&reference.url) {
                issues.push(ValidationIssue {
                    code: ValidationErrorCode::InvalidUrl,
                    severity: self.default_severity(),
                    message: format!("Invalid URL format: {}", reference.url),
                    location: ValidationLocation {
                        file: "web_references.yml".to_string(),
                        line: None,
                        section: Some(reference.id.clone()),
                    },
                    suggestion: "Fix URL format to be valid http/https URL".to_string(),
                    auto_fixable: false,
                });
            }
        }

        ValidationResult::multiple(issues)
    }
}

/// Rule E004: Check README cross-references exist
pub struct ReadmeCrossReferenceRule;

impl ValidationRule for ReadmeCrossReferenceRule {
    fn name(&self) -> &str {
        "readme_cross_reference"
    }

    fn default_severity(&self) -> Severity {
        Severity::Warning
    }

    fn check(&self, data: &CanonicalData) -> ValidationResult {
        let mut issues = Vec::new();

        // Check web references point to existing repos
        for reference in &data.web_references {
            for repo_ref in &reference.related_repos {
                // Try to find by full_name (which is what's stored in related_repos)
                let found = data.repositories
                    .iter()
                    .any(|r| r.metadata.full_name == *repo_ref || r.id == *repo_ref);

                if !found {
                    issues.push(ValidationIssue {
                        code: ValidationErrorCode::BrokenCrossRef,
                        severity: self.default_severity(),
                        message: format!("Web reference links to non-existent repo: {}", repo_ref),
                        location: ValidationLocation {
                            file: "web_references.yml".to_string(),
                            line: None,
                            section: Some(reference.id.clone()),
                        },
                        suggestion: format!("Add repo {} to starred list or remove from related_repos", repo_ref),
                        auto_fixable: false,
                    });
                }
            }
        }

        // Check book references point to existing repos
        for book in &data.books {
            for repo_ref in &book.related_repos {
                let found = data.repositories
                    .iter()
                    .any(|r| r.metadata.full_name == *repo_ref || r.id == *repo_ref);

                if !found {
                    issues.push(ValidationIssue {
                        code: ValidationErrorCode::BrokenCrossRef,
                        severity: self.default_severity(),
                        message: format!("Book links to non-existent repo: {}", repo_ref),
                        location: ValidationLocation {
                            file: "books.yml".to_string(),
                            line: None,
                            section: Some(book.id.clone()),
                        },
                        suggestion: format!("Add repo {} to starred list or remove from related_repos", repo_ref),
                        auto_fixable: false,
                    });
                }
            }
        }

        ValidationResult::multiple(issues)
    }
}

/// Rule E005: Check platform migration completeness
pub struct PlatformMigrationRule;

impl ValidationRule for PlatformMigrationRule {
    fn name(&self) -> &str {
        "platform_migration_complete"
    }

    fn default_severity(&self) -> Severity {
        Severity::Warning
    }

    fn check(&self, data: &CanonicalData) -> ValidationResult {
        let mut issues = Vec::new();

        for repo in &data.repositories {
            // Check if description mentions migration but only has one platform
            let desc_lower = repo.metadata.description.to_lowercase();
            let mentions_migration = desc_lower.contains("moved to") || 
                                    desc_lower.contains("migrated to") ||
                                    (desc_lower.contains("mirror") && desc_lower.contains("codeberg"));

            if mentions_migration && repo.platforms.len() == 1 {
                issues.push(ValidationIssue {
                    code: ValidationErrorCode::PlatformMismatch,
                    severity: self.default_severity(),
                    message: format!("Repository mentions migration but only has one platform: {}", repo.metadata.full_name),
                    location: ValidationLocation {
                        file: "repositories.yml".to_string(),
                        line: None,
                        section: Some(repo.id.clone()),
                    },
                    suggestion: "Add secondary platform URL or update description".to_string(),
                    auto_fixable: false,
                });
            }
        }

        ValidationResult::multiple(issues)
    }
}

/// Rule E006: Check for missing essential metadata
pub struct MissingMetadataRule;

impl ValidationRule for MissingMetadataRule {
    fn name(&self) -> &str {
        "missing_metadata"
    }

    fn default_severity(&self) -> Severity {
        Severity::Info
    }

    fn check(&self, data: &CanonicalData) -> ValidationResult {
        let mut issues = Vec::new();

        for repo in &data.repositories {
            // Check for missing owner (should be split from full_name)
            if repo.metadata.owner.is_empty() {
                issues.push(ValidationIssue {
                    code: ValidationErrorCode::MissingMetadata,
                    severity: self.default_severity(),
                    message: format!("Repository missing owner: {}", repo.metadata.full_name),
                    location: ValidationLocation {
                        file: "repositories.yml".to_string(),
                        line: None,
                        section: Some(repo.id.clone()),
                    },
                    suggestion: "Extract owner from full_name".to_string(),
                    auto_fixable: true,
                });
            }

            // Check for empty description
            if repo.metadata.description.trim().is_empty() {
                issues.push(ValidationIssue {
                    code: ValidationErrorCode::MissingMetadata,
                    severity: self.default_severity(),
                    message: format!("Repository has empty description: {}", repo.metadata.full_name),
                    location: ValidationLocation {
                        file: "repositories.yml".to_string(),
                        line: None,
                        section: Some(repo.id.clone()),
                    },
                    suggestion: "Add description from GitHub".to_string(),
                    auto_fixable: false,
                });
            }
        }

        ValidationResult::multiple(issues)
    }
}

/// Rule for detecting stale content
pub struct StaleContentRule {
    /// Number of days before content is considered stale
    pub stale_days: i64,
}

impl ValidationRule for StaleContentRule {
    fn name(&self) -> &str {
        "stale_content"
    }

    fn default_severity(&self) -> Severity {
        Severity::Info
    }

    fn check(&self, data: &CanonicalData) -> ValidationResult {
        let mut issues = Vec::new();

        // Check web references
        for reference in &data.web_references {
            if reference.is_stale() {
                issues.push(ValidationIssue {
                    code: ValidationErrorCode::MissingMetadata,  // Using closest code
                    severity: self.default_severity(),
                    message: format!("Web reference is stale (>2 years): {}", reference.title),
                    location: ValidationLocation {
                        file: "web_references.yml".to_string(),
                        line: None,
                        section: Some(reference.id.clone()),
                    },
                    suggestion: "Review and update reference, or verify it's still relevant".to_string(),
                    auto_fixable: false,
                });
            }
        }

        ValidationResult::multiple(issues)
    }
}

